set -e
# compute and print report with jq
jq -n '
  def pct(new; old): if old==0 then (if new==0 then 0 else 1/0 end) else ((new-old)/old*100) end;
  def fmt(metric; v):
    if metric=="bounce_rate" or metric=="conversion_rate" then (v*100|tostring + "%")
    elif metric=="avg_session_duration" then (v|tostring + "s")
    else (v|tostring) end;

  {d14:{page_views:52100, unique_visitors:14200, bounce_rate:0.31, avg_session_duration:260, conversion_rate:0.038},
   d15:{page_views:45200, unique_visitors:12800, bounce_rate:0.34, avg_session_duration:245, conversion_rate:0.042}}
  as $d |
  ["page_views","unique_visitors","bounce_rate","avg_session_duration","conversion_rate"]
  | ["metric","2025-12-14","2025-12-15","% change","anomaly (>20%)"],
    (.[] as $m |
      ($d.d14[$m] as $old | $d.d15[$m] as $new |
       ($pc:=pct($new;$old)) |
       [ $m,
         fmt($m;$old),
         fmt($m;$new),
         (if ($pc==($pc)) then ($pc|if .>=0 then "+" else "" end + (.|tostring) + "%") else "+∞%" end),
         (if (($pc|abs)>20) then "YES" else "" end)
       ]
      )
    )
  | .[] | @tsv
' | awk 'BEGIN{FS="\t"; OFS=" | "}
  NR==1{print "| "$1" | "$2" | "$3" | "$4" | "$5" |"; print "|---|---:|---:|---:|:---:|"; next}
  {print "| "$1" | "$2" | "$3" | "$4" | "$5" |"}
'

